(function(globalScope){const root=globalScope;const CONTACT_PAGE_PATH_PATTERN=/\/author\/contact\/contact(?:\/index\.html)?\/?$/;const COPY_BUTTON_SELECTOR='[data-copy-button]';const COPY_FEEDBACK_SELECTOR='[data-copy-feedback]';const CONTACT_CARD_SELECTOR='.content-card';function getLocationOrigin(){return root.location&&typeof root.location.origin==='string'?root.location.origin:'https://example.com';}
function isContactPagePath(urlLike=root.location){if(!urlLike){return false;}
const pathname=typeof urlLike==='string'?new URL(urlLike,getLocationOrigin()).pathname:urlLike.pathname;return CONTACT_PAGE_PATH_PATTERN.test(pathname||'');}
async function copyContactText(text){if(root.navigator&&root.navigator.clipboard&&typeof root.navigator.clipboard.writeText==='function'&&root.isSecureContext){await root.navigator.clipboard.writeText(text);return;}
const textarea=root.document.createElement('textarea');textarea.value=text;textarea.setAttribute('readonly','readonly');textarea.style.position='fixed';textarea.style.top='-9999px';textarea.style.left='-9999px';root.document.body.appendChild(textarea);if(typeof textarea.select==='function'){textarea.select();}
const copied=typeof root.document.execCommand==='function'?root.document.execCommand('copy'):false;root.document.body.removeChild(textarea);if(!copied){throw new Error('copy failed');}}
function updateCopyFeedback(button,message,isError){const feedback=button.parentElement?button.parentElement.querySelector(COPY_FEEDBACK_SELECTOR):null;if(!feedback){return;}
feedback.textContent=message;feedback.dataset.state=isError?'error':'success';if(button.__contactCopyFeedbackTimer){root.clearTimeout(button.__contactCopyFeedbackTimer);}
button.__contactCopyFeedbackTimer=root.setTimeout(()=>{feedback.textContent='';feedback.dataset.state='';},2000);}
function bindCopyButton(button){if(!button||button.dataset.contactCopyBound==='true'){return;}
button.dataset.contactCopyBound='true';button.addEventListener('click',async(event)=>{if(event&&typeof event.preventDefault==='function'){event.preventDefault();}
const value=button.getAttribute('data-copy-value');if(!value){updateCopyFeedback(button,'复制失败，请手动复制',true);return;}
try{await copyContactText(value);updateCopyFeedback(button,'QQ号已复制',false);}catch(error){updateCopyFeedback(button,'复制失败，请手动复制',true);}});}
function bindCardMotion(card){if(!card||card.dataset.contactTiltBound==='true'){return;}
card.dataset.contactTiltBound='true';let isHovering=false;let resetTimer=null;card.addEventListener('mouseenter',()=>{isHovering=true;if(resetTimer!==null){root.clearTimeout(resetTimer);}
card.style.transition='transform 0.2s ease-out';});card.addEventListener('mouseleave',()=>{isHovering=false;resetTimer=root.setTimeout(()=>{card.style.transition='transform 0.6s cubic-bezier(0.34, 1.56, 0.64, 1)';card.style.setProperty('--rX','0deg');card.style.setProperty('--rY','0deg');},400);});card.addEventListener('mousemove',(event)=>{if(!isHovering){return;}
if(resetTimer!==null){root.clearTimeout(resetTimer);}
const rect=card.getBoundingClientRect();const x=(event.clientX-rect.left-rect.width/2)/(rect.width/2);const y=(event.clientY-rect.top-rect.height/2)/(rect.height/2);const rotateY=Math.max(-12,Math.min(12,x*12));const rotateX=Math.max(-12,Math.min(12,y*-12));card.style.transition='transform 0.1s linear';card.style.setProperty('--rX',`${rotateX}deg`);card.style.setProperty('--rY',`${rotateY}deg`);});}
function initializeContactPage(){if(!root.document||!isContactPagePath()){return;}
root.document.querySelectorAll(COPY_BUTTON_SELECTOR).forEach((button)=>{bindCopyButton(button);});root.document.querySelectorAll(CONTACT_CARD_SELECTOR).forEach((card)=>{bindCardMotion(card);});}
function subscribeToPageChanges(callback){if(typeof root.document$!=='undefined'&&typeof root.document$.subscribe==='function'){root.document$.subscribe(()=>{root.requestAnimationFrame(()=>{callback();});});return;}
if(root.document.readyState==='loading'){root.document.addEventListener('DOMContentLoaded',callback,{once:true});return;}
callback();}
if(root.document){subscribeToPageChanges(()=>{initializeContactPage();});}
const contactPageApi={initializeContactPage,isContactPagePath,copyContactText,updateCopyFeedback};root.__contactPage=contactPageApi;if(typeof module!=='undefined'&&module.exports){module.exports=contactPageApi;}})(typeof globalThis.window!=='undefined'?globalThis.window:globalThis);